        "label": "cuRobo",
        "title": "cuRobo: Parallelized Collision-Free Minimum-Jerk Robot Motion Generation",
        "authors": [
          "Sundaralingam",
          "Hari",
          "Fishman"
        ],
        "year": 2023,
        "super_category": "Decision-Making",
