        "label": "AkinoPDF",
        "title": "Ultrafast Sampling-based Kinodynamic Planning via Differential Flatness",
        "authors": [
          "Duong",
          "Ramsey",
          "Kingston"
        ],
        "year": 2026,
        "super_category": "Decision-Making",
